<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{DailyReport,DailyReportItem,Task};use App\Support\CurrentWorkspace;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class DailyReportController extends Controller{use Concerns;public function index(Request $r){$reports=DailyReport::with('user')->latest('report_date')->paginate(15);return view('tenant.daily-reports.index',compact('reports'));}public function create(){return view('tenant.daily-reports.create',['report'=>new DailyReport,'tasks'=>Task::latest()->get()]);}public function store(Request $r,CurrentWorkspace $cw){$this->requirePerm('tenant.daily_reports.submit');$w=$this->ws($cw);$data=$this->data($r,$w);$report=DailyReport::create($data+['workspace_id'=>$w->id,'user_id'=>$r->user()->id,'status'=>'draft']);$this->items($r,$report,$w);return redirect('/daily-reports/'.$report->id);}public function show(DailyReport $dailyReport){return view('tenant.daily-reports.show',['report'=>$dailyReport->load('items.task','user','reviewer')]);}public function edit(DailyReport $dailyReport){abort_unless(in_array($dailyReport->status,['draft','rejected'],true),403);return view('tenant.daily-reports.create',['report'=>$dailyReport->load('items'),'tasks'=>Task::latest()->get()]);}public function update(Request $r,DailyReport $dailyReport,CurrentWorkspace $cw){abort_unless(in_array($dailyReport->status,['draft','rejected'],true),403);$dailyReport->update($this->data($r,$this->ws($cw))+['status'=>'draft']);$dailyReport->items()->delete();$this->items($r,$dailyReport,$this->ws($cw));return redirect('/daily-reports/'.$dailyReport->id);}public function submit(Request $r,DailyReport $dailyReport,CurrentWorkspace $cw){$this->requirePerm('tenant.daily_reports.submit');abort_unless($dailyReport->user_id===$r->user()->id && in_array($dailyReport->status,['draft','rejected'],true),403);$deadline=$this->deadline($cw);$dailyReport->update(['status'=>'submitted','submitted_at'=>now(),'is_late'=>$deadline?now()->greaterThan($deadline):false]);return redirect('/daily-reports/'.$dailyReport->id);}private function data(Request $r,$w):array{return $r->validate(['report_date'=>['required','date',Rule::unique('daily_reports')->where('workspace_id',$w->id)->where('user_id',$r->user()->id)->ignore($r->route('dailyReport'))],'completed_summary'=>'nullable|string','in_progress_summary'=>'nullable|string','pending_summary'=>'nullable|string','blocker_summary'=>'nullable|string','tomorrow_plan'=>'nullable|string']);}private function items(Request $r,DailyReport $report,$w):void{foreach((array)$r->input('items',[]) as $i=>$item){if(empty($item['title']))continue;DailyReportItem::create(['workspace_id'=>$w->id,'daily_report_id'=>$report->id,'task_id'=>$item['task_id']??null,'item_type'=>$item['item_type']??'completed','title'=>$item['title'],'description'=>$item['description']??null,'time_spent_minutes'=>$item['time_spent_minutes']??null,'sort_order'=>$i]);}}private function deadline(CurrentWorkspace $cw){$s=$cw->required()->settings;return $s?now($s->timezone?:config('app.timezone'))->setTimeFromTimeString($s->daily_report_deadline?:'23:59:59'):null;}}
